#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 100005
#define MAX_L 100005

// Define the structure for a tree node
typedef struct Node {
    int l, r;
    int value;
    char *str;
} Node;

// Function to create a new node
Node *createNode(int l, int r, int value) {
    Node *node = (Node *)malloc(sizeof(Node));
    node->l = l;
    node->r = r;
    node->value = value;
    node->str = NULL;
    return node;
}

// Function to perform DFS and assign strings to leaves
void dfs(Node *node, char *str, int len) {
    if (node->l == -1) {
        // Leaf node, assign the string
        node->str = (char *)malloc((len + 1) * sizeof(char));
        strcpy(node->str, str);
    } else {
        // Non-leaf node, recursively call DFS for left and right sons
        char *newStr = (char *)malloc((len + 2) * sizeof(char));
        strcpy(newStr, str);
        newStr[len] = 'L';
        newStr[len + 1] = '\0';
        dfs(node->l, newStr, len + 1);
        newStr[len] = 'R';
        dfs(node->r, newStr, len + 1);
        free(newStr);
    }
}

// Function to check if the tree is leaf-sorted
int isLeafSorted(Node *node) {
    if (node->l == -1) {
        // Leaf node, return 1 if the string is in the correct order
        return strcmp(node->str, node->value) <= 0;
    } else {
        // Non-leaf node, recursively call isLeafSorted for left and right sons
        return isLeafSorted(node->l) && isLeafSorted(node->r);
    }
}

// Function to find the minimum number of operations required to make the tree leaf-sorted
int minOperations(Node *node) {
    if (node->l == -1) {
        // Leaf node, return 0 if the string is in the correct order
        return strcmp(node->str, node->value) <= 0 ? 0 : 1;
    } else {
        // Non-leaf node, recursively call minOperations for left and right sons
        int leftOps = minOperations(node->l);
        int rightOps = minOperations(node->r);
        return leftOps + rightOps;
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Node *nodes = (Node **)malloc(N * sizeof(Node *));
        for (int i = 0; i < N; i++) {
            int l, r;
            scanf("%d %d", &l, &r);
            nodes[i] = createNode(l, r, r);
        }
        dfs(nodes[0], "", 0);
        if (isLeafSorted(nodes[0])) {
            printf("0\n");
        } else {
            printf("%d\n", minOperations(nodes[0]));
        }
        for (int i = 0; i < N; i++) {
            free(nodes[i]->str);
            free(nodes[i]);
        }
        free(nodes);
    }
    return 0;
}

